#include <vector>
#include <heap>
#include <algorithm>

using namespace std;

long long solve(vector<long long> piles) {
    // Sort the array
    sort(piles.begin(), piles.end());
    long long total = 0;

    // Use a min-heap to keep track of the middle elements
    priority_queue<long long, vector<long long>, greater<long long>> heap;

    // Iterate through the array in steps of 3
    for (int i = 0; i < piles.size(); i += 3) {
        // Push the middle element of the current triplet into the heap
        heap.push(piles[i + 1]);
    }

    // Sum up all the middle elements from the heap
    while (!heap.empty()) {
        total += heap.top();
        heap.pop();
    }

    return total;
}
